16	// InstallPackage downloads the source release tarball and copies declared install mappings
17	// into projectRoot. It records installed files (project-relative when possible) in the
18	// returned InstalledEntry.
19	//
20	// Compatibility shim: this is the historical entrypoint that downloads from a
21	// remote tarball. New callers should pick the explicit From* variant that
22	// matches their source (Remote/Dir/FS).
23	func InstallPackage(pkg *Package, projectRoot string) (InstalledEntry, error) {
24		return InstallPackageFromRemote(pkg, projectRoot)
25	}
26	
27	// InstallPackageFromRemote downloads the source release tarball and installs
28	// the package via the shared core install implementation.
29	func InstallPackageFromRemote(pkg *Package, projectRoot string) (InstalledEntry, error) {
30		entry := InstalledEntry{
31			Name:        pkg.Name,
32			Version:     pkg.Version,
33			Type:        pkg.Type,
34			Source:      pkg.Source,
35			InstalledAt: time.Now(),
36		}
37	
38		// FEAT-015 early validation: if the package argument already declares a
39		// home-rooted Root.Target, reject it before doing any I/O. The post-
40		// manifest check below covers manifest-supplied targets after download.
41		if pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
42			return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
43		}
44	
45		tmpDir, err := os.MkdirTemp("", "ddx-install-"+pkg.Name+"-*")
46		if err != nil {
47			return entry, fmt.Errorf("creating temp dir: %w", err)
48		}
49		defer func() { _ = os.RemoveAll(tmpDir) }()
50	
51		tarballURL := githubTarballURL(pkg.Source, pkg.Version)
52		extractedDir, err := downloadAndExtract(tarballURL, tmpDir)
53		if err != nil {
54			return entry, fmt.Errorf("downloading %s: %w", tarballURL, err)
55		}
56	
57		return installFromExtractedDir(pkg, extractedDir, projectRoot, entry)
58	}
59	
60	// InstallPackageFromDir installs the package from an already-extracted source
61	// directory (e.g. a local checkout) via the shared core install implementation.
62	// Network is not used.
63	func InstallPackageFromDir(pkg *Package, sourceDir, projectRoot string) (InstalledEntry, error) {
64		entry := InstalledEntry{
65			Name:        pkg.Name,
66			Version:     pkg.Version,
67			Type:        pkg.Type,
68			Source:      pkg.Source,
69			InstalledAt: time.Now(),
70		}
71	
72		if pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
73			return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
74		}
75	
76		return installFromExtractedDir(pkg, sourceDir, projectRoot, entry)
77	}
78	
79	// InstallPackageFromFS installs the package from an in-memory or embedded
80	// filesystem (e.g. //go:embed) rooted at the package directory. The FS is
81	// materialized into a temporary directory and passed through the shared core
82	// install implementation. Network is not used.
83	func InstallPackageFromFS(pkg *Package, src iofs.FS, projectRoot string) (InstalledEntry, error) {
84		entry := InstalledEntry{
85			Name:        pkg.Name,
86			Version:     pkg.Version,
87			Type:        pkg.Type,
88			Source:      pkg.Source,
89			InstalledAt: time.Now(),
90		}
91	
92		if src == nil {
93			return entry, fmt.Errorf("InstallPackageFromFS: source fs is nil")
94		}
95	
96		if pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
97			return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
98		}
99	
100		tmpDir, err := os.MkdirTemp("", "ddx-install-fs-"+pkg.Name+"-*")
101		if err != nil {
102			return entry, fmt.Errorf("creating temp dir: %w", err)
103		}
104		defer func() { _ = os.RemoveAll(tmpDir) }()
105	
106		if err := materializeFS(src, tmpDir); err != nil {
107			return entry, fmt.Errorf("materializing embedded package: %w", err)
108		}
109	
110		return installFromExtractedDir(pkg, tmpDir, projectRoot, entry)
111	}
112	
113	// installFromExtractedDir is the shared core install routine used by the
114	// Remote, Dir, and FS entrypoints. It assumes the package contents are
115	// already present on disk at sourceDir.
116	func installFromExtractedDir(pkg *Package, sourceDir, projectRoot string, entry InstalledEntry) (InstalledEntry, error) {
117		// Switch into projectRoot so relative install targets resolve against the
118		// project, not the caller's cwd. This keeps copyMapping, ExpandHome, and
119		// the recorded entry.Files paths project-relative.
120		if projectRoot != "" {
121			absProject, absErr := filepath.Abs(projectRoot)
122			if absErr == nil {
123				if origDir, gwdErr := os.Getwd(); gwdErr == nil && origDir != absProject {
124					if err := os.Chdir(absProject); err == nil {
125						defer func() { _ = os.Chdir(origDir) }()
126					}
127				}
128			}
129		}
130	
131		if manifestPkg, manifestMissing, manifestIssues, manifestErr := LoadPackageManifestWithFallback(sourceDir, pkg); manifestErr == nil || (os.IsNotExist(manifestErr) && manifestMissing) {
132			if manifestPkg != nil {
133				pkg = manifestPkg
134			}
135		} else {
136			if len(manifestIssues) > 0 {
137				return entry, fmt.Errorf("validating package manifest: %s", JoinValidationIssues(manifestIssues))
138			}
139			return entry, fmt.Errorf("loading package manifest: %w", manifestErr)
140		}
141	
142		if pkg.Install.Root == nil {
143			pkg.Install.Root = &InstallMapping{
144				Source: ".",
145				Target: defaultPackageRootTarget(pkg.Name),
146			}
147		}
148	
149		// FEAT-015: plugin install targets must be project-relative. Manifests
150		// that try to write into the user's home are rejected so plugins can't
151		// pollute global state.
152		if strings.HasPrefix(pkg.Install.Root.Target, "~") {
153			return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
154		}
155	
156		if issues := ValidatePackageStructure(sourceDir, pkg); len(issues) > 0 {
157			return entry, fmt.Errorf("validating package structure: %s", JoinValidationIssues(issues))
158		}
159	
160		// Process Root mapping — copy the plugin tree into the project-local
161		// install location (e.g. .ddx/plugins/<name>/).
162		var installedRoot string
163		files, err := copyMapping(sourceDir, pkg.Install.Root)
164		if err != nil {
165			return entry, fmt.Errorf("installing plugin root: %w", err)
166		}
167		entry.Files = append(entry.Files, files...)
168		installedRoot = ExpandHome(pkg.Install.Root.Target)
169	
170		// Ensure declared executables have the execute bit set.
171		for _, rel := range pkg.Install.Executable {
172			p := filepath.Join(installedRoot, filepath.FromSlash(rel))
173			if info, err := os.Stat(p); err == nil && !info.IsDir() {
174				_ = os.Chmod(p, info.Mode()|0111)
175			}
176		}
177	
178		// Process Skills via the manifest mappings. Each mapping copies real files
179		// into its declared target. No symlinks are ever created -- this is the
180		// cross-platform invariant that FEAT-015 relies on.
181		if len(pkg.Install.Skills) > 0 {
182			written, err := installMappings(sourceDir, pkg.Install.Skills)
183			if err != nil {
184				return entry, fmt.Errorf("installing skills: %w", err)
185			}
186			entry.Files = append(entry.Files, written...)
187		}
188	
189		// Process Scripts mapping — copy the script to the target path.
190		// If the target is already a symlink, the developer is managing it
191		// themselves (e.g. symlink to their git checkout) — skip with a notice.
192		if pkg.Install.Scripts != nil {
193			dst := ExpandHome(pkg.Install.Scripts.Target)
194			if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
195				target, _ := os.Readlink(dst)
196				fmt.Fprintf(os.Stderr, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
197				entry.Files = append(entry.Files, dst)
198			} else {
199				srcDir := sourceDir
200				if installedRoot != "" {
201					srcDir = installedRoot
202				}
203				files, err := copyMapping(srcDir, pkg.Install.Scripts)
204				if err != nil {
205					return entry, fmt.Errorf("installing scripts: %w", err)
206				}
207				entry.Files = append(entry.Files, files...)
208	
209				// Ensure the installed script is executable.
210				if info, err := os.Stat(dst); err == nil && !info.IsDir() {
211					_ = os.Chmod(dst, info.Mode()|0111)
212				}
213			}
214		}
215	
216		// Process symlinks.
217		for _, sym := range pkg.Install.Symlinks {
218			src := ExpandHome(sym.Source)
219			dst := ExpandHome(sym.Target)
220	
221			// Create parent dir if needed.
222			if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
223				return entry, fmt.Errorf("creating symlink dir %s: %w", filepath.Dir(dst), err)
224			}
225	
226			// Remove existing symlink/file if present.
227			if _, err := os.Lstat(dst); err == nil {
228				if err := os.RemoveAll(dst); err != nil {
229					return entry, fmt.Errorf("removing existing %s: %w", dst, err)
230				}
231			}
232	
233			if err := os.Symlink(src, dst); err != nil {
234				return entry, fmt.Errorf("creating symlink %s -> %s: %w", dst, src, err)
235			}
236			entry.Files = append(entry.Files, dst)
237		}
238	
239		return entry, nil
240	}
241	
242	// materializeFS writes every regular file in src into destDir, preserving the
243	// relative path layout. Symlinks in the source FS (uncommon for embed.FS) are
244	// skipped to keep the cross-platform invariant FEAT-015 relies on.
245	func materializeFS(src iofs.FS, destDir string) error {
246		return iofs.WalkDir(src, ".", func(p string, d iofs.DirEntry, err error) error {
247			if err != nil {
248				return err
249			}
250			if p == "." {
251				return nil
252			}
253			target := filepath.Join(destDir, filepath.FromSlash(p))
254			if d.IsDir() {
255				return os.MkdirAll(target, 0o755)
256			}
257			if d.Type()&os.ModeSymlink != 0 {
258				return nil
259			}
260			if !d.Type().IsRegular() {
261				return nil
262			}
263			data, readErr := iofs.ReadFile(src, p)
264			if readErr != nil {
265				return readErr
266			}
267			if err := os.MkdirAll(filepath.Dir(target), 0o755); err != nil {
268				return err
269			}
270			return os.WriteFile(target, data, 0o644)
271		})
272	}
273	
274	// installMappings applies each mapping relative to srcDir and returns the
275	// project-relative files written by those mappings.
276	func installMappings(srcDir string, mappings []InstallMapping) ([]string, error) {
277		var written []string
278		for _, mapping := range mappings {
279			files, err := copyMapping(srcDir, &mapping)
280			if err != nil {
281				return nil, fmt.Errorf("copy %q -> %q: %w", mapping.Source, mapping.Target, err)
282			}
283			written = append(written, files...)
284		}
285		return written, nil
286	}
