21	// newInstallCommand creates the "ddx install <name>" command.
22	func (f *CommandFactory) newInstallCommand() *cobra.Command {
23		cmd := &cobra.Command{
24			Use:   "install <name>",
25			Short: "Install a package or resource",
26			Long: `Install a package or resource from the DDx registry into the
27	current project under .ddx/plugins/<name>/.
28	
29	Examples:
30	  ddx install helix                        # Install HELIX workflow
31	  ddx install helix --force                # Reinstall even if already up to date
32	  ddx plugin install helix --local ../helix --force
33	  ddx install persona/strict-code-reviewer # Install a single persona`,
34			Args: cobra.ExactArgs(1),
35			RunE: f.runInstall,
36		}
37		cmd.Flags().BoolP("force", "f", false, "Reinstall even if already at the latest version")
38		cmd.Flags().String("local", "", "Install from a local directory instead of the registry")
39		return cmd
40	}
41	
42	func (f *CommandFactory) runInstall(cmd *cobra.Command, args []string) error {
43		out := cmd.OutOrStdout()
44		force, _ := cmd.Flags().GetBool("force")
45		name := args[0]
46	
47		// Ensure install operations resolve relative paths against the project
48		// root (WorkingDir), not the caller's cwd. This prevents creating stale
49		// .ddx/ workspaces in subdirectories.
50		if f.WorkingDir != "" {
51			origDir, _ := os.Getwd()
52			if origDir != f.WorkingDir {
53				if err := os.Chdir(f.WorkingDir); err == nil {
54					defer func() { _ = os.Chdir(origDir) }()
55				}
56			}
57		}
58	
59		// Handle --local: install from a local directory instead of registry.
60		if localPath, _ := cmd.Flags().GetString("local"); localPath != "" {
61			return f.installLocal(name, localPath, force, out)
62		}
63	
64		if registry.IsResourcePath(name) {
65			// Individual resource install (e.g. "persona/strict-code-reviewer")
66			fmt.Fprintf(out, "Installing resource %s...\n", name)
67			entry, err := registry.InstallResource(name)
68			if err != nil {
69				return fmt.Errorf("install resource: %w", err)
70			}
71	
72			state, err := registry.LoadState()
73			if err != nil {
74				return fmt.Errorf("loading state: %w", err)
75			}
76			state.AddOrUpdate(entry)
77			if err := registry.SaveState(state); err != nil {
78				return fmt.Errorf("saving state: %w", err)
79			}
80	
81			fmt.Fprintf(out, "Installed %s\n", name)
82			return nil
83		}
84	
85		// Package install (e.g. "helix")
86		reg := registry.BuiltinRegistry()
87		pkg, err := reg.Find(name)
88		if err != nil {
89			return err
90		}
91	
92		// Fetch actual latest version from GitHub (overrides hardcoded registry version).
93		if release, err := update.FetchLatestReleaseForRepo(pkg.Source); err == nil {
94			pkg.Version = strings.TrimPrefix(release.TagName, "v")
95		}
96	
97		// Check if already installed at the latest version.
98		state, err := registry.LoadState()
99		if err == nil {
100			for _, e := range state.Installed {
101				if e.Name == name {
102					if e.Version == pkg.Version {
103						if !force {
104							fmt.Fprintf(out, "%s %s is already up to date\n", e.Name, e.Version)
105							return nil
106						}
107						fmt.Fprintf(out, "Reinstalling %s %s...\n", e.Name, e.Version)
108					} else {
109						fmt.Fprintf(out, "Updating %s from %s to %s...\n", e.Name, e.Version, pkg.Version)
110					}
111				}
112			}
113		}
114	
115		// Capture old file list before installing so we can remove stale files.
116		var oldFiles []string
117		if state != nil {
118			if old := state.FindInstalled(name); old != nil {
119				oldFiles = append([]string{}, old.Files...)
120			}
121		}
122	
123		fmt.Fprintf(out, "Installing %s %s from %s...\n", pkg.Name, pkg.Version, pkg.Source)
124	
125		entry, err := registry.InstallPackage(pkg, f.WorkingDir)
126		if err != nil {
127			return fmt.Errorf("install package: %w", err)
128		}
129	
130		removed := removeStaleFilesFromInstall(oldFiles, entry.Files)
131		if removed > 0 {
132			fmt.Fprintf(out, "Removed %d stale file(s)\n", removed)
133		}
134	
135		state, stateErr := registry.LoadState()
136		if stateErr != nil {
137			return fmt.Errorf("loading state: %w", stateErr)
138		}
139		state.AddOrUpdate(entry)
140		if err := registry.SaveState(state); err != nil {
141			return fmt.Errorf("saving state: %w", err)
142		}
143	
144		fmt.Fprintf(out, "Installed %s %s (%d file(s))\n", pkg.Name, pkg.Version, len(entry.Files))
145	
146		// Auto-commit skill symlinks and other trackable changes.
147		commitPluginChanges(name, pkg.Version)
148	
149		return nil
150	}
