165	func removeStaleFilesFromInstall(oldFiles []string, newFiles []string) int {
166		if len(oldFiles) == 0 {
167			return 0
168		}
169	
170		newSet := make(map[string]bool, len(newFiles))
171		for _, f := range newFiles {
172			newSet[f] = true
173		}
174	
175		removed := 0
176		for _, f := range oldFiles {
177			if newSet[f] {
178				continue
179			}
180			if installPathContainsAny(f, newFiles) {
181				continue
182			}
183			expanded := registry.ExpandHome(f)
184			if err := os.RemoveAll(expanded); err == nil {
185				removed++
186			}
187		}
188		return removed
189	}
