207	// commitPluginChanges stages and commits plugin-related changes in the working tree.
208	// Non-fatal: if git operations fail (not a repo, nothing to commit), it's silently skipped.
209	func commitPluginChanges(name, version string) {
210		// Stage the project-local plugin tree and the skill copies.
211		paths := []string{
212			filepath.Join(".ddx", "plugins", name) + string(filepath.Separator),
213			".agents/skills/",
214			".claude/skills/",
215		}
216		ctx := context.Background()
217		for _, p := range paths {
218			if _, err := os.Stat(p); err == nil {
219				gitAdd := internalgit.Command(ctx, "", "add", p)
220				_ = gitAdd.Run()
221			}
222		}
223	
224		// Check if there's anything to commit.
225		status := internalgit.Command(ctx, "", "diff", "--cached", "--quiet")
226		if status.Run() == nil {
227			return // nothing staged
228		}
229	
230		msg := fmt.Sprintf("chore: install %s %s", name, version)
231		gitCommit := internalgit.Command(ctx, "", "commit", "-m", msg)
232		_ = gitCommit.Run()
233	}
