510	func installLocalSkillSymlinks(pluginRoot, projectRoot string, force bool) ([]string, error) {
511		sourceRoot, entries, err := localSkillSourceEntries(pluginRoot)
512		if err != nil {
513			return nil, err
514		}
515		if len(entries) == 0 {
516			return nil, nil
517		}
518	
519		var written []string
520		for _, entry := range entries {
521			if !entry.IsDir() && entry.Type()&os.ModeSymlink == 0 {
522				continue
523			}
524			name := entry.Name()
525			src := filepath.Join(sourceRoot, name)
526			if _, err := os.Stat(filepath.Join(src, "SKILL.md")); err != nil {
527				return nil, fmt.Errorf("%s: missing SKILL.md: %w", src, err)
528			}
529			for _, surface := range []string{".agents/skills", ".claude/skills"} {
530				dst := filepath.Join(projectRoot, filepath.FromSlash(surface), name)
531				if err := prepareSymlinkTarget(dst, force); err != nil {
532					return nil, err
533				}
534				if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
535					return nil, fmt.Errorf("creating skills dir: %w", err)
536				}
537				target, err := filepath.Rel(filepath.Dir(dst), src)
538				if err != nil {
539					target = src
540				}
541				if err := os.Symlink(target, dst); err != nil {
542					return nil, fmt.Errorf("linking skill %s -> %s: %w", dst, target, err)
543				}
544				written = append(written, filepath.Join(filepath.FromSlash(surface), name))
545			}
546		}
547		return written, nil
548	}
