656	func filterLocalInstallValidationIssues(root string, issues []registry.ValidationIssue) []registry.ValidationIssue {
657		filtered := issues[:0]
658		roots := localInstallRootAliases(root)
659		for _, issue := range issues {
660			if rel, ok := localInstallIssueRel(roots, issue.Path); ok && shouldSkipLocalInstallIssue(rel) {
661				continue
662			}
663			filtered = append(filtered, issue)
664		}
665		return filtered
666	}
