668	func localInstallRootAliases(root string) []string {
669		seen := map[string]bool{}
670		var roots []string
671		add := func(path string) {
672			if strings.TrimSpace(path) == "" {
673				return
674			}
675			abs, err := filepath.Abs(path)
676			if err != nil {
677				abs = path
678			}
679			if !seen[abs] {
680				seen[abs] = true
681				roots = append(roots, abs)
682			}
683			if resolved, err := filepath.EvalSymlinks(abs); err == nil && resolved != "" && !seen[resolved] {
684				seen[resolved] = true
685				roots = append(roots, resolved)
686			}
687		}
688		add(root)
689		return roots
690	}
