692	func localInstallIssueRel(roots []string, path string) (string, bool) {
693		for _, candidate := range localInstallPathAliases(path) {
694			for _, root := range roots {
695				rel, err := filepath.Rel(root, candidate)
696				if err != nil || rel == "." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) || rel == ".." {
697					continue
698				}
699				return filepath.ToSlash(rel), true
700			}
701		}
702		return "", false
703	}
704	
705	func localInstallPathAliases(path string) []string {
706		seen := map[string]bool{}
707		var aliases []string
708		add := func(candidate string) {
709			if strings.TrimSpace(candidate) == "" {
710				return
711			}
712			abs, err := filepath.Abs(candidate)
713			if err != nil {
714				abs = candidate
715			}
716			if !seen[abs] {
717				seen[abs] = true
718				aliases = append(aliases, abs)
719			}
720		}
721		add(path)
722		if resolved, err := filepath.EvalSymlinks(path); err == nil && resolved != "" {
723			add(resolved)
724		}
725		dir := filepath.Dir(path)
726		base := filepath.Base(path)
727		if resolvedDir, err := filepath.EvalSymlinks(dir); err == nil && resolvedDir != "" {
728			add(filepath.Join(resolvedDir, base))
729		}
730		return aliases
731	}
