733	func shouldSkipLocalInstallIssue(rel string) bool {
734		rel = strings.TrimPrefix(filepath.ToSlash(rel), "./")
735		for _, prefix := range []string{
736			".git/",
737			".ddx/plugins/",
738			".ddx/agent-logs/",
739			".ddx/executions/",
740			".ddx/exec-runs.d/",
741			".ddx/server/",
742			".ddx/tsnet/",
743			".ddx/workers/",
744			"node_modules/",
745			"tmp/",
746			"website/node_modules/",
747			"website/public/",
748			"website/resources/",
749			"website/test-results/",
750			"website/playwright-report/",
751		} {
752			if strings.HasPrefix(rel, prefix) {
753				return true
754			}
755		}
756		return false
757	}
758	
759	func shouldSkipLocalInstallPath(rel string, info os.FileInfo) bool {
760		rel = strings.TrimPrefix(filepath.ToSlash(rel), "./")
761		if rel == "." || rel == "" {
762			return false
763		}
764		if shouldSkipLocalInstallIssue(rel + "/") {
765			return true
766		}
767		if info.IsDir() {
768			base := filepath.Base(rel)
769			return base == ".git" || base == "node_modules" || base == "tmp"
770		}
771		return false
772	}
