864	
865	func (f *CommandFactory) runVerify(cmd *cobra.Command, args []string) error {
866		out := cmd.OutOrStdout()
867	
868		state, err := registry.LoadState()
869		if err != nil {
870			return fmt.Errorf("loading state: %w", err)
871		}
872	
873		if len(state.Installed) == 0 {
874			fmt.Fprintln(out, "No packages installed.")
875			return nil
876		}
877	
878		var totalIssues int
879		for _, entry := range state.Installed {
880			var issues []string
881			for _, f := range entry.Files {
882				expanded := registry.ExpandHome(f)
883				info, err := os.Lstat(expanded)
884				if os.IsNotExist(err) {
885					issues = append(issues, fmt.Sprintf("  missing: %s", f))
886					continue
887				}
888				if err != nil {
889					issues = append(issues, fmt.Sprintf("  error: %s: %v", f, err))
890					continue
891				}
892				// Check symlinks resolve.
893				if info.Mode()&os.ModeSymlink != 0 {
894					target, err := os.Readlink(expanded)
895					if err != nil {
896						issues = append(issues, fmt.Sprintf("  broken symlink: %s", f))
897						continue
898					}
899					// Resolve relative symlinks against their parent directory.
900					if !filepath.IsAbs(target) {
901						target = filepath.Join(filepath.Dir(expanded), target)
902					}
903					if _, err := os.Stat(target); os.IsNotExist(err) {
904						issues = append(issues, fmt.Sprintf("  broken symlink: %s -> %s", f, target))
905					}
906				}
907			}
908	
909			if len(issues) == 0 {
910				fmt.Fprintf(out, "%s %s: OK (%d files)\n", entry.Name, entry.Version, len(entry.Files))
911			} else {
912				fmt.Fprintf(out, "%s %s: %d issue(s)\n", entry.Name, entry.Version, len(issues))
913				for _, issue := range issues {
914					fmt.Fprintln(out, issue)
915				}
916				totalIssues += len(issues)
917			}
918		}
919	
920		if totalIssues > 0 {
921			return fmt.Errorf("%d integrity issue(s) found — run 'ddx install <name> --force' to repair", totalIssues)
922		}
923		return nil
924	}
