func localSkillSourceEntries(pluginRoot string, mappings []registry.InstallMapping) (string, []os.DirEntry, error) {
	candidates := localSkillSourceCandidates(pluginRoot, mappings)
	for _, candidate := range candidates {
		entries, err := os.ReadDir(candidate)
		if err == nil && len(entries) > 0 {
