// localSkillSourceCandidates returns directories to search for skill sub-dirs
// during a local install. When the package manifest declares install.skills[*],
// the manifest-declared sources are tried first (project-local install honors
// the package's stated layout). The historical fallbacks (.agents/skills and
// skills) remain as a compatibility path for plugins without manifests.
func localSkillSourceCandidates(pluginRoot string, mappings []registry.InstallMapping) []string {
	seen := map[string]bool{}
	var out []string
	add := func(rel string) {
		rel = strings.TrimSpace(rel)
		if rel == "" {
			return
		}
		path := filepath.Join(pluginRoot, filepath.FromSlash(strings.TrimSuffix(rel, "/")))
		if seen[path] {
			return
		}
		seen[path] = true
		out = append(out, path)
	}
	for _, m := range mappings {
		add(m.Source)
	}
	add(".agents/skills")
	add("skills")
	return out
}

